def test_flag_default_value_processing(runner, default, flag_value, type, expected_default, expected_flag):
    @click.command()
    @click.option("--value", flag_value=flag_value, default=default, type=type)
    def cmd(value):
        click.echo(repr(value))

    result = runner.invoke(cmd, [])
    assert not result.exception
    assert result.output == f"{expected_default!r}\n"

    result = runner.invoke(cmd, ["--value"])
    assert not result.exception
    assert result.output == f"{expected_flag!r}\n"
